    about:{
      title:'About RelahConvert',hero_h1_1:'About',hero_h1_em:'RelahConvert',
      hero_p:'Free image tools built for everyone — with privacy at the core.',
      s1_h:'Who We Are',
      s1_p1:'RelahConvert is a free, browser-based image tool suite built for anyone who needs to convert, compress, or resize images quickly — without uploading files to a server.',
      s1_p2:'We believe your files are yours. Every tool on RelahConvert runs entirely in your browser. Nothing is ever sent to our servers, stored, or shared.',
      s2_h:'Our Mission',s2_p:'To make professional image tools accessible to everyone, for free, with zero compromise on privacy.',
      s3_h:'Why RelahConvert?',s3_f1:'100% free, no account required',s3_f2:'Files never leave your device',s3_f4:'Works on any modern browser',
    },
    contact:{
      title:'Contact Us — RelahConvert',hero_h1_1:'Contact',hero_h1_em:'Us',
      hero_p:"Have a question, suggestion, or found a bug? We'd love to hear from you.",
      s1_h:'Get in Touch',s1_p:"Send us an email and we'll get back to you within 1–2 business days.",
      s2_h:'What to Include',s2_p1:'For the fastest response, please mention:',
      s2_p2:'• The tool you were using (e.g. Compress Image, JPG to PNG)<br>• A description of the issue or suggestion<br>• Your browser and device type (e.g. Chrome on Windows)',
    },
    privacy:{
      title:'Privacy Policy — RelahConvert',hero_h1_1:'Privacy',hero_h1_em:'Policy',updated:'Last updated: March 2026',
      s1_h:'No File Uploads',s1_p:'All image processing on RelahConvert happens locally in your browser. Your files are never uploaded to, stored on, or accessed by our servers. Exception: the HTML to Image tool transmits the URL you enter to a third-party rendering service to capture the screenshot — no image files are uploaded by you.',
      s2_h:'Data We Collect',s2_p1:'We collect minimal anonymous usage data such as page views and browser type.',s2_p2:'We do not collect names, email addresses, or any personally identifiable information.',
      s3_h:'Cookies',s3_p:'We use only essential cookies. No advertising or tracking cookies. See our <a href="/cookies">Cookie Policy</a>.',
      s4_h:'Third Parties',s4_p:'We do not sell, share, or transfer your data to any third parties.',
    },
    terms:{
      title:'Terms & Conditions — RelahConvert',hero_h1_1:'Terms &amp;',hero_h1_em:'Conditions',updated:'Last updated: March 2026',
      s1_h:'Use of Service',s1_p:'RelahConvert is provided free of charge for personal and commercial use. You agree not to use the service for any unlawful purpose.',
      s2_h:'No Warranty',s2_p:'The service is provided "as is" without warranties of any kind.',
      s3_h:'Limitation of Liability',s3_p:'RelahConvert and its operators are not liable for any loss or damage resulting from your use of the service.',
      s4_h:'Intellectual Property',s4_p:'The RelahConvert name, logo, and site design are our intellectual property.',
      s5_h:'Changes to Terms',s5_p:'We reserve the right to update these terms at any time.',
    },
    cookies:{
      title:'Cookie Policy — RelahConvert',hero_h1_1:'Cookie',hero_h1_em:'Policy',updated:'Last updated: March 2026',
      s1_h:'What Are Cookies?',s1_p:'Cookies are small text files stored on your device when you visit a website.',
      s2_h:'What We Use',s2_p:'RelahConvert uses only essential cookies. We do not use advertising, analytics, or tracking cookies.',
      s3_h:'Third-Party Cookies',s3_p:'We do not allow third-party cookies on RelahConvert.',
      s4_h:'Managing Cookies',s4_p:"You can disable or clear cookies at any time through your browser settings.",
    },
