      'remove-pdf':{
        h2a:'Comment supprimer des pages d\'un PDF en trois étapes',
        steps:['<strong>Téléchargez votre PDF</strong> — cliquez sur « Sélectionner un PDF » ou glissez-déposez.','<strong>Marquez les pages à supprimer</strong> — cliquez sur les pages que vous souhaitez supprimer.','<strong>Téléchargez</strong> — enregistrez un nouveau PDF sans les pages supprimées.'],
        h2b:'Le meilleur outil gratuit de suppression de pages PDF',
        body:'<p>Supprimez les pages indésirables de n\'importe quel document PDF. Cliquez pour marquer les pages à supprimer, puis téléchargez un PDF propre sans ces pages. Supprimez les pages vierges, les pages de couverture, les publicités ou tout contenu dont vous n\'avez pas besoin. Tout le traitement s\'effectue dans votre navigateur.</p>',
        h3why:'Pourquoi supprimer des pages PDF ?',
        why:'Supprimer les pages inutiles réduit la taille du fichier, élimine le contenu non pertinent et crée des documents plus propres pour le partage. Supprimez les pages vierges, le contenu dupliqué ou les sections indésirables.',
        faqs:[
          {q:'Comment supprimer des pages d\'un PDF ?',a:'Téléchargez votre PDF, cliquez sur les pages que vous souhaitez supprimer et cliquez sur « Supprimer et télécharger ».'},
          {q:'Puis-je annuler la suppression de pages ?',a:'Le fichier original n\'est pas modifié. Si vous devez recommencer, téléchargez à nouveau l\'original.'},
          {q:'Y a-t-il un nombre minimum de pages ?',a:'Oui. Au moins une page doit rester dans le document.'},
          {q:'La suppression de pages affecte-t-elle les pages restantes ?',a:'Non. Les pages restantes sont copiées telles quelles sans perte de qualité.'},
          {q:'Mes fichiers sont-ils envoyés quelque part ?',a:'Non. Tout le traitement s\'effectue localement dans votre navigateur.'},
        ],
        links:[{href:'/extract-pdf',label:'Extraire pages'},{href:'/split-pdf',label:'Diviser PDF'},{href:'/merge-pdf',label:'Fusionner PDF'},{href:'/compress-pdf',label:'Compresser PDF'}],
      },
      'add-page-numbers':{
        h2a:'Comment ajouter des numéros de page à un PDF en trois étapes',
        steps:['<strong>Téléchargez votre PDF</strong> — cliquez sur « Sélectionner un PDF » ou glissez-déposez.','<strong>Configurez la numérotation</strong> — choisissez la position, la taille de police, le format et le numéro de départ.','<strong>Téléchargez</strong> — enregistrez votre PDF numéroté.'],
        h2b:'Le meilleur outil gratuit de numérotation de pages PDF',
        body:'<p>Ajoutez des numéros de page à n\'importe quel document PDF avec un contrôle total sur la position, la taille et le format. Placez les numéros en haut ou en bas, à gauche, au centre ou à droite. Choisissez parmi les formats « 1 », « Page 1 », « 1 sur N » ou « Page 1 sur N ». Tout le traitement s\'effectue dans votre navigateur.</p>',
        h3why:'Pourquoi ajouter des numéros de page à un PDF ?',
        why:'Les numéros de page facilitent la navigation, les références et les discussions autour des documents. Ils sont essentiels pour les rapports, les manuels, les documents juridiques et tout document multi-pages destiné à être lu dans l\'ordre.',
        faqs:[
          {q:'Puis-je choisir où apparaissent les numéros de page ?',a:'Oui. Choisissez parmi 6 positions : haut-gauche, haut-centre, haut-droite, bas-gauche, bas-centre ou bas-droite.'},
          {q:'Puis-je commencer la numérotation à partir d\'une page spécifique ?',a:'Oui. Définissez le numéro de départ à n\'importe quelle valeur — utile si votre PDF fait partie d\'un document plus grand.'},
          {q:'Quels formats de numérotation sont disponibles ?',a:'Choisissez parmi « 1 », « Page 1 », « 1 sur N » ou « Page 1 sur N ».'},
          {q:'Puis-je changer la taille de police ?',a:'Oui. Définissez n\'importe quelle taille de police entre 8 et 36 points.'},
          {q:'Mes fichiers sont-ils envoyés quelque part ?',a:'Non. Tout le traitement s\'effectue localement dans votre navigateur.'},
        ],
        links:[{href:'/merge-pdf',label:'Fusionner PDF'},{href:'/compress-pdf',label:'Compresser PDF'},{href:'/rotate-pdf',label:'Pivoter PDF'},{href:'/split-pdf',label:'Diviser PDF'}],
      },
