        links:[{href:'/merge-pdf',label:'Combinar PDF'},{href:'/split-pdf',label:'Dividir PDF'},{href:'/compress-pdf',label:'Comprimir PDF'},{href:'/rotate-pdf',label:'Rotar PDF'}],
