        links:[{href:'/merge-pdf',label:'Combinar PDF'},{href:'/extract-pdf',label:'Extraer páginas'},{href:'/remove-pdf',label:'Eliminar páginas'},{href:'/compress-pdf',label:'Comprimir PDF'}],
