    meme_generator_title:'Δημιουργός meme',meme_generator_desc:'Δημιουργήστε memes online. Επιλέξτε πρότυπο ή ανεβάστε εικόνα. Ιδιωτικό — στο πρόγραμμα περιήγησης.',meme_generator_upload_btn:'Ανέβασμα',meme_generator_template_btn:'Πρότυπο',meme_generator_add_text_btn:'Προσθήκη κειμένου',meme_generator_add_image_btn:'Προσθήκη εικόνας',meme_generator_download_btn:'Λήψη meme',meme_generator_text_inside:'Κείμενο εντός',meme_generator_text_outside:'Κείμενο εκτός',meme_generator_band_color:'Χρώμα λωρίδας',meme_generator_top_text:'Πάνω κείμενο',meme_generator_bottom_text:'Κάτω κείμενο (προαιρετικό)',
