    blur_face_title:'Rozmyj',blur_face_title_em:'twarz',blur_face_sub:'Rozmyj twarze na zdjeciach. Automatycznie lub recznie. Do 25 obrazow. Prywatne — dziala w przegladarce.',blur_face_upload:'Przeslij obraz',blur_face_download:'Pobierz obraz',blur_face_amount:'Stopien rozmycia',blur_face_detecting:'Wykrywanie twarzy…',blur_face_none:'Nie wykryto twarzy. Sprobuj wyrazniejszego zdjecia lub uzyj Dodaj rozmycie.',blur_face_found:'twarz(y) wykryte',blur_face_manual:'Dodaj rozmycie',blur_face_auto:'Auto wykrywanie',blur_face_mode:'Tryb',blur_face_select_mode:'Wybierz tryb aby rozpoczac.',blur_face_draw:'Kliknij i przeciagnij na obrazie aby rozmyc obszar.',blur_face_editor:'Edytor rozmycia',blur_face_regions:'Rozmyte obszary',blur_face_download_zip:'Pobierz wszystko jako ZIP',blur_face_reset:'Przeslij nowy obraz',blur_face_images_label:'Obrazy',blur_face_drop:'Upusc obrazy tutaj lub kliknij aby przeslac',blur_face_drop_sub:'JPG, PNG, WebP · Do 25 obrazow · Maks 200MB',blur_face_processing:'Przetwarzanie',blur_face_creating_zip:'Tworzenie ZIP…',blur_face_batch_failed:'Pobieranie zbiorcze nie powiodlo sie',
